#!/bin/bash\n\n# Upveil Technology - Vercel Postgres Setup Script\n# This script helps set up the Vercel Postgres database\n\necho \"🚀 Upveil Technology - Vercel Postgres Setup\"\necho \"=============================================\"\necho \"\"\n\n# Check if .env exists\nif [ ! -f .env ]; then\n    echo \"❌ .env file not found!\"\n    echo \"Please create .env from .env.example and add your DATABASE_URL\"\n    exit 1\nfi\n\necho \"✅ .env file found\"\necho \"\"\n\n# Check if DATABASE_URL is set\nif ! grep -q \"DATABASE_URL\" .env; then\n    echo \"❌ DATABASE_URL not found in .env\"\n    echo \"Please add your Vercel Postgres connection string to .env\"\n    exit 1\nfi\n\necho \"✅ DATABASE_URL is configured\"\necho \"\"\n\necho \"📦 Installing dependencies...\"\nnpm install\n\necho \"\"\necho \"🔄 Generating Prisma client...\"\nnpm run prisma:generate\n\necho \"\"\necho \"🗄️  Running database migrations...\"\nnpm run prisma:migrate\n\necho \"\"\necho \"🌱 Seeding initial data...\"\nnpm run prisma:seed\n\necho \"\"\necho \"✅ Setup complete!\"\necho \"\"\necho \"Next steps:\"\necho \"1. Update your .env with the correct DATABASE_URL from Vercel\"\necho \"2. Test locally: npm start\"\necho \"3. Deploy to Vercel: git push\"\n", "path": "setup.sh